import{_ as t,o as a,c as p,ag as i}from"./chunks/framework.DlAClNku.js";const u=JSON.parse('{"title":"第 4 章 贵族专制、民主政治和系统设计（Aristocracy, Democracy, and System Design）","description":"","frontmatter":{},"headers":[],"relativePath":"ch4.md","filePath":"ch4.md","lastUpdated":1777275530000}'),o={name:"ch4.md"};function s(r,e,n,l,c,h){return a(),p("div",null,[...e[0]||(e[0]=[i('<h1 id="第-4-章-贵族专制、民主政治和系统设计-aristocracy-democracy-and-system-design" tabindex="-1">第 4 章 贵族专制、民主政治和系统设计（Aristocracy, Democracy, and System Design） <a class="header-anchor" href="#第-4-章-贵族专制、民主政治和系统设计-aristocracy-democracy-and-system-design" aria-label="Permalink to &quot;第 4 章 贵族专制、民主政治和系统设计（Aristocracy, Democracy, and System Design）&quot;">​</a></h1><p>大教堂是艺术史上无与伦比的成就。它的原则既不乏味也不混乱……真正达到了风格上的极致，完成这件作品的艺术家们，完全领会和吸收了以往的成功经验，也完全掌握了他们那个时代的技术，而且在应用的时候做到了恰如其分，绝不轻率，也绝不花哨。</p><p>正是 Jean d&#39;Orbais 构思了建筑的整体设计，这个设计得到了后继者的认同，至少在本质上如此。这也是这个建筑如此和谐统一的原因之一。</p><p>——兰斯大教堂指南</p><p>This great church is an incomparable work of art. There is neither aridity nor confusion in the tenets it sets forth. . . . It is the zenith of a style, the work of artists who had understood and assimilated all their predecessors&#39; successes, in complete possession of the techniques of their times, but using them without indiscreet display nor gratuitous feats of skill.</p><p>It was Jean d&#39;Orbais who undoubtedly conceived the general plan of the building, a plan which was respected, at least in its essential elements, by his successors. This is one of the reasons for the extreme coherence and unity of the edifice.</p><p>——REIMS CATHEDRAL GUIDEBOOK</p><h2 id="概念一致性" tabindex="-1">概念一致性 <a class="header-anchor" href="#概念一致性" aria-label="Permalink to &quot;概念一致性&quot;">​</a></h2><p>在绝大多数欧洲大教堂中，不同时代、不同建筑师所建造的各个部分，在设计风格或结构上往往存在诸多差异。后来的建筑师总是试图在前人的基础上有所&quot;提高&quot;，以彰显自己在风格和品味上的变化。于是，宏伟的哥特式教堂上附着了宁静的诺曼底风格翼廊——它在颂扬上帝荣耀的同时，也展示了建筑师自身的骄傲。</p><p>与之截然不同的，是法国城市兰斯（Reims）建筑风格上令人叹服的一致性。那种设计上的统一，与精彩的细节一样令人赞叹。正如旅游指南所述，这种风格的完整与纯粹来自八代建筑师的自我约束与牺牲精神——每一位都甘愿抑制自己的某些创意，以成全整体设计的纯粹。这同样体现了上帝的荣耀，也彰显了祂拯救那些沉溺于自我骄傲之人的力量。</p><p>对于计算机系统而言，尽管它们通常无需历经几个世纪来建造，但绝大多数系统所呈现出的概念差异与不一致，远比欧洲的大教堂严重。这通常并不是因为由不同的设计师开发，而是因为设计被分割成许多部分，由许多人分别完成。</p><p>我主张，在系统设计中，概念完整性应当是最重要的考量。也就是说，为了体现一系列连贯的设计思路，宁可舍弃一些不协调的特性和改进，也不主张那些各自独立、无法整合的系统——哪怕这些系统中包含许多出色的设计。在本章及其后两章中，我们将阐明这一主题在编程系统设计中的重要性：</p><ul><li>如何实现概念的完整性？</li><li>这样的主张是否意味着需要一位精英架构师的贵族专制，并且由此压制了那些普通实现人员的创造力？</li><li>如何防止架构师产出无法实现或代价高昂的规格说明，使大家陷入困境？</li><li>如何与实现人员就规格说明的细节充分沟通，确保设计被正确理解并精确融入产品？</li></ul><h2 id="获得概念的完整性" tabindex="-1">获得概念的完整性 <a class="header-anchor" href="#获得概念的完整性" aria-label="Permalink to &quot;获得概念的完整性&quot;">​</a></h2><p>编程系统（软件）的目的是让计算机更容易使用。为此，计算机配备了语言和各种工具，这些工具本质上也是程序，受编程语言控制。然而使用这些工具是有代价的：软件的外部描述规模，往往是计算机系统本身说明文档的十倍。用户固然可以轻松找到某个特定功能，却不得不面对太多的选择、记忆太多的选项和格式。</p><p>只有当这些功能节省下来的时间，超过用户花在学习、记忆和查阅手册上的时间，易用性才真正得到了提升。现代编程系统确实节省了可观的时间，但近年来，随着功能的不断叠加，收益与成本的比率已在逐渐下降。IBM 650 那份朴素的易用性至今仍萦绕在我脑海——那套系统甚至没有汇编器，也没有任何其他软件。</p><p>既然目标是易用性，那么&quot;功能与理解复杂度之比&quot;才是系统设计的终极评判标准。单纯的功能强大，或单纯的易于上手，都不足以成为好设计的判据。</p><p>然而这一点被广泛误解。OS/360 凭借其复杂强大的功能深受开发者推崇；设计人员的工作好坏往往以功能多寡而非简洁程度来衡量。另一方面，PDP-10 的分时系统以简洁和概念上的精炼著称，尽管其功能与 OS/360 不在同一量级。但是，一旦以易用性作为标准，功能和易用性单独来看都是片面的，都只触及了真正目标的一半。</p><p>在给定功能级别下，能以最简洁、最直接的方式说明事情的系统，才是最好的。但仅有简洁（simplicity）还不够——Mooers 的 TRAC 语言和 Algol 68 用少量独特的基本概念实现了简洁，却并不直白（straightforward）。要表达一件待完成的事情，常常需要以意料不到的复杂方式组合基本元素；仅仅了解基本元素和组合规则还不够，还需要学习晦涩的惯用法以及实践中的组合技巧。简洁和直白，来自概念的完整性。系统的每个部分必须体现相同的原则和一致的权衡取舍；在语法上采用相同的约定，在语义上保持一致的相似性。因此，易用性在本质上要求设计的一致性和概念上的完整性。</p><h2 id="贵族专制统治和民主政治" tabindex="-1">贵族专制统治和民主政治 <a class="header-anchor" href="#贵族专制统治和民主政治" aria-label="Permalink to &quot;贵族专制统治和民主政治&quot;">​</a></h2><p>概念完整性要求设计必须由一个人，或者极少数相互默契的人来把控。</p><p>而进度压力则要求大量人员参与系统开发。化解这一矛盾有两种途径：第一，仔细区分体系结构设计与具体实现；第二，就是上一章所讨论的那种崭新的团队组建方式。</p><p>对于大型项目，将体系结构工作与具体实现相分离，是获得概念完整性的有力手段。我亲眼目睹了这一方法在 IBM Stretch 计算机和 360 计算机产品线上取得的巨大成功，也同样看到了它在 360 操作系统开发中由于推行不力而遭受的失败。</p><p>系统的体系结构（architecture），指的是完整而详尽的用户接口规格说明。对计算机而言，是编程手册；对编译器而言，是语言手册；对控制程序而言，是语言和函数调用手册；对整个系统而言，是用户完成所有工作所需查阅的手册集合。</p><p>因此，系统架构师正如建筑设计师一样，是用户利益的代言人。架构师的工作，是运用专业知识维护用户的真正利益，而非迎合销售人员的鼓吹。</p><p>体系结构与实现必须仔细加以区分。正如 Blaauw 所说：&quot;体系结构陈述的是发生了什么，实现描述的是如何做到。&quot;他举了一个简单的例子——时钟。时钟的体系结构包括表盘、指针和上弦旋钮。孩子一旦了解了时钟的外部结构，便能从手表或教堂的大钟上辨认时间。而时钟的实现，则描述了表壳内部的一切——选用了众多动力驱动方式中的某一种，以及众多计时精度方案中的某一种。</p><p>以 System/360 为例，同一套计算机体系结构可以用 9 种不同型号来实现；而同一种实现——Model 30 的数据通路、内存和微代码方案——则可以支持 4 种不同的体系结构：System/360 计算机、拥有 224 个独立逻辑子通道的复杂通道、选择通道，以及 1401 计算机。</p><p>这同样适用于编程系统。以美国的 Fortran IV 标准为例，它是许多编译器共同遵循的体系结构规范，在这一体系结构下存在多种实现：以文本为核心的、以编译器为核心的、快速编译与优化的，以及注重语法检查的实现。类似地，任何汇编语言和任务控制语言，都允许有多种编译器或调度程序的实现方式。</p><p>现在，让我们来面对这个充满感情色彩的问题——贵族统治与民主政治。架构师难道不是新的特权阶层？他们不就是一批智识精英，专门来指点那些&quot;可怜的&quot;实现人员该怎么工作吗？是否所有的创造性活动都被精英所独占，实现人员不过是机器中的齿轮？难道不应该遵循民主原则，广泛采纳所有人员的好想法，以获得更好的产品，而不是将规格说明的工作局限于少数人？</p><p>最后这个问题最容易回答。我当然不认为只有架构师才有好主意——新的概念往往来自实现者或用户。然而，我一贯坚持，并且所有经验都使我确信：系统的概念完整性决定了使用的容易程度。那些无法与系统基本概念融合的好想法和特性，最好搁置不用。如果出现了许多重要但相互不兼容的构想，就应当舍弃原有设计，重新整合不同的基本概念，在新的基础上重新开始。</p><p>关于贵族专制的问题，则必须分两方面回答。就架构师必须是少数人这一点而言，答案是肯定的：他们的工作成果生命周期比实现者的更长，他们始终处于解决用户问题、维护用户利益的核心位置。要实现系统概念上的完整性，就必须对这些概念加以把控。这确实是一种贵族专制——但无需为此道歉。</p><p>而对于第二个问题，答案是否定的。编制外部规格说明，并不比具体设计实现更富有创造性，它只是一种性质不同的创造工作。在给定体系结构框架下的设计实现，同样需要同样的创造力、同样新颖的思路和卓越的才华。事实上，产品的性价比在很大程度上取决于实现人员，正如易用性在很大程度上取决于架构师。</p><p>许多行业的案例都证明，纪律和约束对于创造是有益的。正如某位艺术家的格言所言：&quot;没有限制，就没有艺术。&quot;最差的建筑往往诞生于预算漫无边际的项目。巴赫每周必须创作一首形式严格的康塔塔，但这显然并未压制他的创造力。我也相信，如果当年对 Stretch 计算机施加更严格的约束，它将拥有更优秀的体系结构。就我个人而言，System/360 Model 30 的预算约束，反而使其完全受益于 Model 75 的体系结构。</p><p>同样，我观察到，外部的体系结构规范实际上增强而非限制了实现团队的创造力。一旦他们将注意力集中在前人从未解决的问题上，创意便源源涌现。而在缺乏架构约束的实现团队中，大量的想法和争议都耗费在结构层面的决策上，对具体实现本身的关注反而减少了。</p><p>这种情况我见过多次，R. W. Conway 也证实了这一点。他在康奈尔大学的小组曾编写 PL/I 编译器。他说：&quot;最终我们决定直接支持原版语言，不做任何修改或增强，因为关于语言本身的争论已经耗尽了我们所有的时间和精力。&quot;</p><h2 id="实现人员等待期间能做什么" tabindex="-1">实现人员等待期间能做什么？ <a class="header-anchor" href="#实现人员等待期间能做什么" aria-label="Permalink to &quot;实现人员等待期间能做什么？&quot;">​</a></h2><p>一次耗资数百万美元的失误是令人痛苦的经历，却也是终生难忘的教训。那个我们策划和组织 OS/360 外部规格说明编写工作的夜晚，时常重现在我脑海中。我与体系结构经理和程序实现经理共同制订进度计划，明确责任分工。</p><p>体系结构经理有 10 名出色的员工，他表示他们能够出色地完成规格说明的编写工作。但这项任务需要 10 个月，比允许的时间多出 3 个月。</p><p>程序实现经理有 150 人。他认为，在体系结构团队的配合下，他们能够按时完成高质量、切合实际的说明；而如果把这项工作完全交给体系结构团队，他的 150 人就只能白白等待 10 个月。</p><p>体系结构经理的回应是：如果由程序实现团队来负责，结果同样不会按时完成，一样会推迟 3 个月，而且质量更差。我把工作交给了程序实现团队，结果果然如此。体系结构经理的两个判断都得到了证实。此外，概念完整性的缺失导致系统开发和修改的代价更加高昂——我估计至少额外增加了一年的调试时间。</p><p>造成那次错误决策的因素很多，但最关键的是：进度压力，以及让 150 名程序员有事可做的强烈愿望。这正是我想着重强调的致命陷阱。</p><p>当有人提议由体系结构团队来编写所有外部规格说明时，程序员们提出了三点反对意见：</p><ul><li>规格说明中的功能过于繁多，对实际成本的考量太少</li><li>架构师独揽了所有创造发明的乐趣，剥夺了实现人员的创造空间</li><li>体系结构团队工作进展缓慢，许多实现人员只能坐等</li></ul><p>其中第一点确实是一个真实的风险，下一章将专门讨论；而另外两点则是彻头彻尾的误解。如前所述，实现工作同样是高水平的创造性活动。具体实现所带来的创造和发明机会，并不会因为有了外部规格说明而大为减少——恰恰相反，明确的规范会激发创造力，整个产品也因此受益。</p><p>最后一点反对意见涉及时间顺序和阶段安排。简要的回答是：等规格说明完成后再雇用实现人员。盖楼也是这么做的。</p><p>但在计算机行业，节奏极快，时间进度常被压缩到极限，规格说明与开发实现之间能有多少重叠呢？</p><p>正如 Blaauw 所指出的，整个创造性活动包含三个独立的阶段：体系结构（architecture）、设计实现（implementation）和物理实现（realization）。在实践中，它们往往可以同时启动、并行推进。</p><p>以计算机设计为例，只要实现人员对手册有了初步设想，对技术有了相对清晰的思路，并且已经确定了良好定义的成本目标，工作便可启动：可以开始设计数据通路、控制序列、整体系统划分等；同时，工具的选择和调整工作，特别是文档存档系统和设计自动化系统，也可以同步展开。</p><p>在物理实现层面，电路、板卡、线缆、机箱、电源和内存的设计、细化和文档编制，同样可以与体系结构及设计实现并行进行。</p><p>在编程系统的开发中，这一原理同样适用。在外部规格说明完成之前，实现人员已经有许多事情可以着手。只要有若干最终将纳入规格说明的系统功能雏形，工作便可展开：首先，必须确立明确的时间和空间目标，了解产品运行的平台配置；接着，可以开始设计模块边界、数据结构、算法及各类工具；此外，还需要与架构师保持沟通，协调相关问题。</p><p>与此同时，在物理实现层面，同样有许多工作可以提前开展。编程本身是一种技术积累，尤其是面对新型机器时，在库的适配、系统管理以及搜索排序算法等方面，有大量工作需要处理。</p><p>概念完整性确实要求系统只体现唯一的设计理念，用户所见的规格说明来自少数人的思想。将工作划分为体系结构、设计实现和物理实现，并不意味着这种开发模式需要更长的时间。经验表明恰恰相反，整个系统开发得更快，所需的测试时间也更少。与工作的水平分割相比，垂直分层从根本上大幅减少了劳动量，沟通因此大为简化，概念完整性也得到了显著提升。</p>',52)])])}const m=t(o,[["render",s]]);export{u as __pageData,m as default};
